import React, { useState, useEffect, useRef } from "react";
import "../styles/GeneralChat.css";

const GeneralChat = () => {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const chatEndRef = useRef(null);

  useEffect(() => {
    setMessages([
      {
        sender: "ai",
        text: "Hi 👋 I’m your AI mental health assistant. How are you feeling today?",
      },
    ]);
  }, []);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const detectMood = (text) => {
    const t = text.toLowerCase();

    if (t.includes("happy") || t.includes("good") || t.includes("great"))
      return "happy";
    if (t.includes("sad") || t.includes("down") || t.includes("cry"))
      return "sad";
    if (t.includes("angry") || t.includes("mad") || t.includes("furious"))
      return "angry";
    if (t.includes("anxious") || t.includes("stress") || t.includes("worried"))
      return "anxious";

    return null; // ❗ important
  };

  const getAIReply = (mood) => {
    if (!mood)
      return "I’m listening 💙 Tell me more about what’s on your mind.";

    const replies = {
      happy: "That’s wonderful 🌟 What made you feel happy?",
      sad: "I’m really sorry 💙 Want to share what’s bothering you?",
      angry: "That sounds frustrating 😔 Let’s slow down together.",
      anxious: "That can be overwhelming 😟 What’s making you anxious?",
    };

    return replies[mood];
  };

  const saveMood = (mood) => {
    if (!mood) return;

    const history = JSON.parse(localStorage.getItem("moodHistory")) || [];
    history.push({
      mood,
      time: new Date().toISOString(),
    });

    localStorage.setItem("moodHistory", JSON.stringify(history));
  };

  const handleSend = () => {
    if (!input.trim()) return;

    setMessages((prev) => [...prev, { sender: "user", text: input }]);

    const mood = detectMood(input);
    saveMood(mood);

    setTimeout(() => {
      setMessages((prev) => [
        ...prev,
        { sender: "ai", text: getAIReply(mood) },
      ]);
    }, 600);

    setInput("");
  };

  return (
    <div className="chat-page">
      <div className="chat-card">

        <div className="chat-header">
          <span>🧠</span>
          <h2>General Chat</h2>
        </div>

        <div className="chat-body">
          {messages.map((msg, i) => (
            <div key={i} className={`chat-bubble ${msg.sender}`}>
              {msg.text}
            </div>
          ))}
          <div ref={chatEndRef} />
        </div>

        <div className="chat-input">
          <input
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Type how you feel..."
            onKeyDown={(e) => e.key === "Enter" && handleSend()}
          />
          <button onClick={handleSend}>Send</button>
        </div>

      </div>
    </div>
  );
};

export default GeneralChat;
